namespace sv_0b3dba2e1ed442e8907c4de7b154058a;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor)
{
    public static ThemeInfo Default => new(Theme.Light, "#0d6efd");
}

@* Displays current theme — works in the static layout via CascadingValueSource *@

<span class="theme-indicator" style="color: @Theme?.AccentColor;">
    @GetThemeIcon() @Theme?.Theme.ToString()
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetThemeIcon() => Theme?.Theme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select" value="@currentTheme" @onchange="OnThemeChanged">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@accentColor" @onchange="OnAccentChanged" />
</div>

<p>
    Current: <strong style="color: @accentColor;">@currentTheme</strong>
    — accent <code>@accentColor</code>
</p>

@code {
    private Theme currentTheme;
    private string accentColor = ThemeInfo.Default.AccentColor;

    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentTheme = Theme.Theme;
            accentColor = Theme.AccentColor;
        }
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        currentTheme = Enum.Parse<Theme>(e.Value!.ToString()!);
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentTheme, accentColor));
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        accentColor = e.Value!.ToString()!;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentTheme, accentColor));
    }
}

